/** @module organization-details-edit */

import { getComponentStyles } from '@auth0/universal-components-core';
import * as React from 'react';

import { OrganizationDetails } from '@/components/auth0/my-organization/shared/organization-management/organization-details/organization-details';
import { GateKeeper } from '@/components/auth0/shared/gate-keeper/gate-keeper';
import { Header } from '@/components/auth0/shared/header';
import { StyledScope } from '@/components/auth0/shared/styled-scope';
import { Spinner } from '@/components/ui/spinner';
import { useOrganizationDetailsEdit } from '@/hooks/my-organization/use-organization-details-edit';
import { useTheme } from '@/hooks/shared/use-theme';
import { useTranslator } from '@/hooks/shared/use-translator';
import type {
  OrganizationDetailsEditProps,
  OrganizationDetailsEditViewProps,
} from '@/types/my-organization/organization-management/organization-details-edit-types';

/**
 * Organization details edit component.
 * @param props - Component props
 * @param props.schema - Zod validation schema
 * @param props.customMessages - Custom translation messages to override defaults
 * @param props.styling - Custom styling configuration with variables and classes
 * @param props.readOnly - Whether the component is in read-only mode
 * @param props.saveAction - Configuration for the save action
 * @param props.cancelAction - Configuration for the cancel action
 * @param props.hideHeader - Whether to hide the header
 * @param props.backButton - Configuration for the back button
 * @returns JSX element
 * @internal
 */
function OrganizationDetailsEdit(props: OrganizationDetailsEditProps): React.JSX.Element {
  const {
    schema,
    customMessages = {},
    styling = {
      variables: { common: {}, light: {}, dark: {} },
      classes: {},
    },
    readOnly = false,
    saveAction,
    cancelAction,
    hideHeader = false,
    backButton,
  } = props;

  const { organization, isFetchLoading, formActions } = useOrganizationDetailsEdit({
    saveAction,
    cancelAction,
    readOnly,
    customMessages,
  });

  return (
    <GateKeeper isLoading={isFetchLoading} styling={styling}>
      <OrganizationDetailsEditView
        organization={organization}
        isFetchLoading={false}
        schema={schema}
        styling={styling}
        customMessages={customMessages}
        readOnly={readOnly}
        hideHeader={hideHeader}
        backButton={backButton}
        formActions={formActions}
      />
    </GateKeeper>
  );
}

/**
 * @internal
 * @param props - View props
 * @returns Organization Details Edit view element
 */
function OrganizationDetailsEditView({
  organization,
  isFetchLoading,
  schema,
  styling,
  customMessages,
  readOnly,
  hideHeader,
  backButton,
  formActions,
}: OrganizationDetailsEditViewProps) {
  const { isDarkMode } = useTheme();
  const { t } = useTranslator('organization_management.organization_details_edit', customMessages);

  const currentStyles = React.useMemo(
    () => getComponentStyles(styling, isDarkMode),
    [styling, isDarkMode],
  );

  if (isFetchLoading) {
    return (
      <StyledScope style={currentStyles.variables}>
        <div className="flex items-center justify-center min-h-96 w-full">
          <Spinner />
        </div>
      </StyledScope>
    );
  }

  return (
    <StyledScope style={currentStyles.variables}>
      <div className="w-full">
        {!hideHeader && (
          <div className="mb-8">
            <Header
              title={t('header.title', {
                organizationName: organization.display_name || organization.name || '',
              })}
              backButton={
                backButton && {
                  ...backButton,
                  text: t('header.back_button_text'),
                }
              }
            />
          </div>
        )}

        <div className="mb-8">
          <OrganizationDetails
            organization={organization}
            schema={schema?.details}
            customMessages={customMessages?.details}
            styling={styling}
            readOnly={readOnly}
            formActions={formActions}
          />
        </div>
      </div>
    </StyledScope>
  );
}

/**
 * Organization details editing form.
 *
 * A comprehensive component for editing organization details including name,
 * display name, branding, and metadata. Provides form validation, lifecycle
 * hooks for save/cancel actions, and user feedback.
 *
 * @param props - {@link OrganizationDetailsEditProps}
 * @param props.schema - Validation schema overrides
 * @param props.customMessages - Custom i18n message overrides
 * @param props.styling - CSS variables and class overrides
 * @param props.readOnly - Render in read-only mode
 * @param props.saveAction - Lifecycle hooks for save operation
 * @param props.cancelAction - Lifecycle hooks for cancel operation
 * @param props.hideHeader - Hide the header section
 * @param props.backButton - Back button configuration
 * @returns Organization details edit component
 *
 * @see {@link OrganizationDetailsEditProps} for full props documentation
 *
 * @example
 * ```tsx
 * <OrganizationDetailsEdit
 *   saveAction={{
 *     onBefore: () => true,
 *     onAfter: (org) => console.log('Saved:', org),
 *   }}
 *   cancelAction={{
 *     onAfter: () => navigate(-1),
 *   }}
 * />
 * ```
 */
export { OrganizationDetailsEdit, OrganizationDetailsEditView };

/**
 * Organization branding details form section.
 * @module branding-details
 * @internal
 */

import { LinkIcon } from 'lucide-react';
import * as React from 'react';

import { Section } from '@/components/auth0/shared/section';
import { ColorPickerInput } from '@/components/ui/color-picker';
import {
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { ImagePreviewField } from '@/components/ui/image-preview-field';
import { useTranslator } from '@/hooks/shared/use-translator';
import type { BrandingDetailsProps } from '@/types/my-organization/organization-management/organization-details-types';

/**
 * BrandingDetails Component
 *
 * Renders the organization branding section with logo and color fields.
 * This component is focused purely on the branding-related form fields.
 * @param props - Component props.
 * @param props.form - React Hook Form instance
 * @param props.customMessages - Custom translation messages to override defaults
 * @param props.className - Optional CSS class name for styling
 * @param props.readOnly - Whether the component is in read-only mode
 * @returns JSX element
 */
export function BrandingDetails({
  form,
  customMessages = {},
  className,
  readOnly = false,
}: BrandingDetailsProps): React.JSX.Element {
  const { t } = useTranslator('organization_management.organization_details', customMessages);

  return (
    <div className={className}>
      <Section title={t('sections.branding.title')}>
        <FormField
          control={form.control}
          name="branding.logo_url"
          render={({ field }) => (
            <FormItem>
              <FormLabel className="text-sm text-(length:--font-size-label) font-medium">
                {t('sections.branding.fields.logo.label')}
              </FormLabel>
              <FormControl>
                <ImagePreviewField
                  {...field}
                  readOnly={readOnly}
                  startAdornment={
                    <div className="p-1.5">
                      <LinkIcon />
                    </div>
                  }
                />
              </FormControl>
              <FormMessage
                className="text-left text-sm text-(length:--font-size-paragraph)"
                role="alert"
              />
              <FormDescription className="text-sm text-(length:--font-size-paragraph) font-normal text-left">
                {t('sections.branding.fields.logo.helper_text')}
              </FormDescription>
            </FormItem>
          )}
        />

        <FormField
          control={form.control}
          name="branding.colors.primary"
          render={({ field }) => (
            <FormItem>
              <FormLabel
                className="text-sm text-(length:--font-size-label) font-medium"
                htmlFor="primary-color"
              >
                {t('sections.branding.fields.primary_color.label')}
              </FormLabel>
              <FormControl>
                <ColorPickerInput {...field} disabled={readOnly} />
              </FormControl>
              <FormMessage
                className="text-left text-sm text-(length:--font-size-paragraph)"
                role="alert"
              />
              <FormDescription className="text-sm text-(length:--font-size-paragraph) font-normal text-left">
                {t('sections.branding.fields.primary_color.helper_text')}
              </FormDescription>
            </FormItem>
          )}
        />

        <FormField
          control={form.control}
          name="branding.colors.page_background"
          render={({ field }) => (
            <FormItem>
              <FormLabel
                className="text-sm text-(length:--font-size-label) font-medium"
                htmlFor="page-background-color"
              >
                {t('sections.branding.fields.page_background_color.label')}
              </FormLabel>
              <FormControl>
                <ColorPickerInput {...field} disabled={readOnly} />
              </FormControl>
              <FormMessage
                className="text-left text-sm text-(length:--font-size-paragraph)"
                role="alert"
              />
              <FormDescription className="text-sm text-(length:--font-size-paragraph) font-normal text-left">
                {t('sections.branding.fields.page_background_color.helper_text')}
              </FormDescription>
            </FormItem>
          )}
        />
      </Section>
    </div>
  );
}

/**
 * Organization details form component.
 * @module organization-details
 * @internal
 */

import type {
  OrganizationDetailsFormValues,
  OrganizationPrivate,
  OrganizationDetailsSchemas,
} from '@auth0/universal-components-core';
import {
  getComponentStyles,
  createOrganizationDetailSchema,
} from '@auth0/universal-components-core';
import { zodResolver } from '@hookform/resolvers/zod';
import * as React from 'react';
import { useForm } from 'react-hook-form';

import { BrandingDetails } from '@/components/auth0/my-organization/shared/organization-management/organization-details/branding-details';
import { SettingsDetails } from '@/components/auth0/my-organization/shared/organization-management/organization-details/settings-details';
import { FormActions } from '@/components/auth0/shared/form-actions';
import { Card } from '@/components/ui/card';
import { Form } from '@/components/ui/form';
import { Separator } from '@/components/ui/separator';
import { Spinner } from '@/components/ui/spinner';
import { useTheme } from '@/hooks/shared/use-theme';
import { useTranslator } from '@/hooks/shared/use-translator';
import { cn } from '@/lib/utils';
import type { OrganizationDetailsProps } from '@/types/my-organization/organization-management/organization-details-types';

/**
 * OrganizationDetails Component
 *
 * A presentation component that displays organization details including settings and branding fields.
 * This component renders form fields for organization configuration in a structured layout with sections.
 * All data, validation, and business logic are handled via props passed from parent components.
 *
 * @param props - Component props.
 * @param props.organization - Organization object
 * @param props.isLoading - Whether the component is in a loading state
 * @param props.schema - Zod validation schema
 * @param props.customMessages - Custom translation messages to override defaults
 * @param props.styling - Custom styling configuration with variables and classes
 * @param props.readOnly - Whether the component is in read-only mode
 * @param props.formActions - Form action buttons configuration
 * @returns JSX element
 */
export function OrganizationDetails({
  organization,
  isLoading = false,
  schema,
  customMessages = {},
  styling = {
    variables: { common: {}, light: {}, dark: {} },
    classes: {},
  },
  readOnly = false,
  formActions,
}: OrganizationDetailsProps): React.JSX.Element {
  const { t } = useTranslator('organization_management.organization_details', customMessages);

  const { isDarkMode } = useTheme();
  const currentStyles = React.useMemo(
    () => getComponentStyles(styling, isDarkMode),
    [styling, isDarkMode],
  );

  const organizationDetailSchema = React.useMemo(() => {
    const mergeFieldConfig = (field: keyof OrganizationDetailsSchemas, defaultError: string) => {
      const fieldConfig = schema?.[field];
      return fieldConfig
        ? {
            ...fieldConfig,
            errorMessage: fieldConfig.errorMessage || defaultError,
          }
        : {
            errorMessage: defaultError,
          };
    };

    return createOrganizationDetailSchema({
      name: mergeFieldConfig('name', t('sections.settings.fields.name.error')),
      displayName: mergeFieldConfig(
        'displayName',
        t('sections.settings.fields.display_name.error'),
      ),
      primaryColor: mergeFieldConfig(
        'primaryColor',
        t('sections.branding.fields.primary_color.error'),
      ),
      logoURL: mergeFieldConfig('logoURL', t('sections.branding.fields.logo.error')),
      backgroundColor: mergeFieldConfig(
        'backgroundColor',
        t('sections.branding.fields.page_background_color.error'),
      ),
    });
  }, [t, schema]);

  const formValues = React.useMemo(
    (): OrganizationDetailsFormValues => ({
      name: organization.name,
      display_name: organization.display_name,
      branding: {
        logo_url: organization.branding.logo_url,
        colors: {
          primary: organization.branding.colors.primary,
          page_background: organization.branding.colors.page_background,
        },
      },
    }),
    [organization],
  );

  const form = useForm<OrganizationDetailsFormValues>({
    resolver: zodResolver(organizationDetailSchema),
    defaultValues: formValues,
    values: formValues,
  });

  const hasUnsavedChanges = form.formState.isDirty;

  const onValid = React.useCallback(
    async (values: OrganizationDetailsFormValues) => {
      if (formActions?.nextAction?.onClick) {
        const payload: OrganizationPrivate = {
          ...values,
          id: organization.id,
        };

        const success = await formActions.nextAction.onClick(payload);

        if (success) {
          form.reset(values, {
            keepValues: true,
            keepDirty: false,
            keepTouched: false,
          });
        }
      }
    },
    [formActions?.nextAction, organization.id, form],
  );

  const handlePreviousAction = React.useCallback(
    (event: Event) => {
      form.reset();
      formActions?.previousAction?.onClick?.(event);
    },
    [form, formActions?.previousAction?.onClick],
  );

  if (isLoading) {
    return <Spinner />;
  }
  return (
    <div style={currentStyles.variables} className="w-full space-y-6">
      <Form {...form}>
        <form onSubmit={form.handleSubmit(onValid)} className="space-y-6">
          <Card
            data-testid="organization-details-card"
            className={cn('p-6', currentStyles.classes?.OrganizationDetails_Card)}
          >
            <div className="space-y-6">
              <SettingsDetails
                form={form}
                readOnly={readOnly}
                customMessages={customMessages}
                className={currentStyles.classes?.OrganizationDetails_SettingsDetails}
              />

              <Separator />

              <BrandingDetails
                form={form}
                readOnly={readOnly}
                customMessages={customMessages}
                className={currentStyles.classes?.OrganizationDetails_BrandingDetails}
              />

              <FormActions
                hasUnsavedChanges={hasUnsavedChanges}
                isLoading={formActions.isLoading}
                nextAction={{
                  label: t('submit_button_label'),
                  disabled:
                    formActions?.nextAction?.disabled ||
                    !hasUnsavedChanges ||
                    formActions.isLoading ||
                    readOnly,
                  type: 'submit',
                }}
                previousAction={{
                  label: t('cancel_button_label'),
                  disabled:
                    formActions?.previousAction?.disabled || formActions.isLoading || readOnly,
                  onClick: handlePreviousAction,
                }}
                showPrevious={formActions?.showPrevious}
                unsavedChangesText={t('unsaved_changes_text')}
                showUnsavedChanges={formActions?.showUnsavedChanges}
                align={formActions?.align}
                className={currentStyles.classes?.OrganizationDetails_FormActions}
              />
            </div>
          </Card>
        </form>
      </Form>
    </div>
  );
}

/**
 * Organization settings details form section.
 * @module settings-details
 * @internal
 */

import * as React from 'react';

import { Section } from '@/components/auth0/shared/section';
import {
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { TextField } from '@/components/ui/text-field';
import { useTranslator } from '@/hooks/shared/use-translator';
import type { SettingsDetailsProps } from '@/types/my-organization/organization-management/organization-details-types';

/**
 * SettingsDetails Component
 *
 * Renders the organization settings section with name and display name fields.
 * This component is focused purely on the settings-related form fields.
 * @param props - Component props.
 * @param props.form - React Hook Form instance
 * @param props.readOnly - Whether the component is in read-only mode
 * @param props.customMessages - Custom translation messages to override defaults
 * @param props.className - Optional CSS class name for styling
 * @returns JSX element
 */
export function SettingsDetails({
  form,
  readOnly = false,
  customMessages = {},
  className,
}: SettingsDetailsProps): React.JSX.Element {
  const { t } = useTranslator('organization_management.organization_details', customMessages);

  return (
    <div className={className}>
      <Section title={t('sections.settings.title')}>
        <FormField
          control={form.control}
          name="name"
          render={({ field }) => (
            <FormItem>
              <FormLabel
                className="text-sm text-(length:--font-size-label) font-medium"
                htmlFor="organization-name"
              >
                {t('sections.settings.fields.name.label')}
              </FormLabel>
              <FormControl>
                <TextField
                  id="organization-name"
                  placeholder={t('sections.settings.fields.name.placeholder')}
                  error={Boolean(form.formState.errors.name)}
                  aria-invalid={Boolean(form.formState.errors.name)}
                  readOnly={readOnly}
                  {...field}
                />
              </FormControl>
              <FormMessage
                className="text-left text-sm text-(length:--font-size-paragraph)"
                role="alert"
              />
              <FormDescription className="text-sm text-(length:--font-size-paragraph) font-normal text-left">
                {t('sections.settings.fields.name.helper_text')}
              </FormDescription>
            </FormItem>
          )}
        />

        <FormField
          control={form.control}
          name="display_name"
          render={({ field }) => (
            <FormItem>
              <FormLabel
                className="text-sm text-(length:--font-size-label) font-medium"
                htmlFor="organization-display-name"
              >
                {t('sections.settings.fields.display_name.label')}
              </FormLabel>
              <FormControl>
                <TextField
                  id="organization-display-name"
                  placeholder={t('sections.settings.fields.display_name.placeholder')}
                  error={Boolean(form.formState.errors.display_name)}
                  aria-invalid={Boolean(form.formState.errors.display_name)}
                  readOnly={readOnly}
                  {...field}
                />
              </FormControl>
              <FormMessage
                className="text-left text-sm text-(length:--font-size-paragraph)"
                role="alert"
              />
              <FormDescription className="text-sm text-(length:--font-size-paragraph) font-normal text-left">
                {t('sections.settings.fields.display_name.helper_text')}
              </FormDescription>
            </FormItem>
          )}
        />
      </Section>
    </div>
  );
}

/**
 * Text field with copy-to-clipboard button.
 * @module copyable-text-field
 * @internal
 */

import { Copy } from 'lucide-react';
import * as React from 'react';

import { Button } from '@/components/ui/button';
import { TextField, type TextFieldProps } from '@/components/ui/text-field';
import { Tooltip, TooltipTrigger, TooltipContent } from '@/components/ui/tooltip';
import { useTranslator } from '@/hooks/shared/use-translator';
import { cn } from '@/lib/utils';

export interface CopyableTextFieldProps extends TextFieldProps {
  onCopy?: () => void;
  copyButtonClassName?: string;
  tooltipSide?: 'top' | 'bottom' | 'left' | 'right';
  tooltipAlign?: 'start' | 'center' | 'end';
  showCopyButton?: boolean;
}

const CopyableTextField = React.forwardRef<HTMLInputElement, CopyableTextFieldProps>(
  (
    {
      onCopy,
      copyButtonClassName,
      tooltipSide = 'top',
      tooltipAlign = 'end',
      readOnly = true,
      endAdornment,
      showCopyButton = true,
      ...props
    },
    ref,
  ) => {
    const { t } = useTranslator('common');
    const [tooltipText, setTooltipText] = React.useState(t('copy'));
    const [tooltipOpen, setTooltipOpen] = React.useState(false);

    const handleCopy = async () => {
      if (props.value) {
        await navigator.clipboard.writeText(String(props.value));
        setTooltipText(t('copied'));
        setTooltipOpen(true);
        setTimeout(() => {
          setTooltipText(t('copy'));
          setTooltipOpen(false);
        }, 1000);
        onCopy?.();
      }
    };

    const copyButton = (
      <Tooltip open={tooltipOpen} onOpenChange={setTooltipOpen}>
        <TooltipTrigger asChild>
          <Button
            type="button"
            variant="ghost"
            size="icon"
            className={cn('h-8 w-8', copyButtonClassName)}
            onClick={handleCopy}
            aria-label={t('copy')}
          >
            <Copy className="h-4 w-4" aria-hidden="true" />
          </Button>
        </TooltipTrigger>
        <TooltipContent side={tooltipSide} align={tooltipAlign} sideOffset={5} className="z-[1000]">
          {tooltipText}
        </TooltipContent>
      </Tooltip>
    );

    return (
      <TextField
        ref={ref}
        readOnly={readOnly}
        {...props}
        endAdornment={
          showCopyButton ? (
            endAdornment ? (
              <div className="flex items-center gap-1">
                {endAdornment}
                {copyButton}
              </div>
            ) : (
              copyButton
            )
          ) : (
            endAdornment
          )
        }
      />
    );
  },
);

CopyableTextField.displayName = 'CopyableTextField';

export { CopyableTextField };

/**
 * Form action buttons component.
 * @module form-actions
 * @internal
 */

import type { ActionButton } from '@auth0/universal-components-core';
import * as React from 'react';

import { Button } from '@/components/ui/button';
import { Spinner } from '@/components/ui/spinner';
import { cn } from '@/lib/utils';

export interface FormActionsProps<T = void> {
  hasUnsavedChanges?: boolean;
  isLoading?: boolean;
  nextAction?: Partial<ActionButton<T>>;
  previousAction?: Partial<ActionButton<T>>;
  showPrevious?: boolean;
  showNext?: boolean;
  showUnsavedChanges?: boolean;
  align?: 'left' | 'right';
  className?: string;
  unsavedChangesText?: string;
}

const DEFAULT_NEXT_ACTION: ActionButton = {
  type: 'submit',
  label: 'Save',
  variant: 'primary',
  onClick: () => {},
};

const DEFAULT_PREVIOUS_ACTION: ActionButton = {
  label: 'Cancel',
  variant: 'outline',
  onClick: () => {},
};

export const FormActions: React.FC<FormActionsProps> = ({
  hasUnsavedChanges = false,
  isLoading = false,
  nextAction,
  previousAction,
  className,
  showPrevious = true,
  showNext = true,
  showUnsavedChanges = true,
  align = 'right',
  unsavedChangesText = 'Unsaved changes',
}) => {
  const nextButtonProps = React.useMemo(
    () => ({ ...DEFAULT_NEXT_ACTION, ...nextAction }),
    [nextAction],
  );

  const previousButtonProps = React.useMemo(
    () => ({ ...DEFAULT_PREVIOUS_ACTION, ...previousAction }),
    [previousAction],
  );

  const handleNextClick = React.useCallback(
    (e: React.MouseEvent<HTMLButtonElement>) => {
      nextButtonProps.onClick(e.nativeEvent);
    },
    [nextButtonProps.onClick],
  );

  const handlePreviousClick = React.useCallback(
    (e: React.MouseEvent<HTMLButtonElement>) => {
      previousButtonProps.onClick(e.nativeEvent);
    },
    [previousButtonProps.onClick],
  );

  const showUnsavedIndicator = showUnsavedChanges && hasUnsavedChanges;
  const isPreviousVisible = showUnsavedChanges ? showPrevious && hasUnsavedChanges : showPrevious;

  return (
    <div
      className={cn(
        'flex flex-row items-center gap-2 p-2',
        align === 'right' ? 'justify-end' : 'justify-start',
        className,
      )}
    >
      {showUnsavedIndicator && (
        <span className="text-sm text-muted-foreground">{unsavedChangesText}</span>
      )}

      {showPrevious && (
        <Button
          type="button"
          variant={previousButtonProps.variant}
          size={previousButtonProps.size}
          onClick={handlePreviousClick}
          disabled={
            previousButtonProps.disabled || isLoading || (showUnsavedChanges && !hasUnsavedChanges)
          }
          className={cn(
            'FormActions-previous',
            showUnsavedChanges && !isPreviousVisible && 'invisible',
          )}
          aria-hidden={showUnsavedChanges && !isPreviousVisible}
          tabIndex={isPreviousVisible ? 0 : -1}
        >
          {previousButtonProps.label}
        </Button>
      )}

      {showNext && (
        <Button
          type={nextButtonProps.type}
          variant={nextButtonProps.variant}
          size={nextButtonProps.size}
          disabled={nextButtonProps.disabled || isLoading}
          className="FormActions-next min-w-17.5"
          {...(nextButtonProps.type !== 'submit' && { onClick: handleNextClick })}
        >
          {isLoading ? (
            <Spinner
              colorScheme={nextButtonProps.variant === 'destructive' ? 'primary' : 'foreground'}
              size="sm"
              aria-hidden="true"
            />
          ) : (
            <>
              {nextButtonProps.icon && (
                <span className="mr-2" aria-hidden="true">
                  {nextButtonProps.icon as React.ReactNode}
                </span>
              )}
              {nextButtonProps.label}
            </>
          )}
        </Button>
      )}
    </div>
  );
};

/**
 * GateKeeper component for guarding content during loading, MFA step-up, and 5xx error states.
 * @module gate-keeper
 * @internal
 */

import {
  type ComponentStyling,
  type MfaRequiredError,
  getComponentStyles,
  getStatusCode,
  isMfaRequiredError,
  normalizeMfaRequiredError,
} from '@auth0/universal-components-core';
import { RefreshCcw } from 'lucide-react';
import React, { useCallback, useMemo, useState } from 'react';

import { MfaWizard } from '@/components/auth0/shared/gate-keeper/mfa-step-up/mfa-wizard';
import { StyledScope } from '@/components/auth0/shared/styled-scope';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardFooter, CardTitle } from '@/components/ui/card';
import { Dialog, DialogContent } from '@/components/ui/dialog';
import { Spinner } from '@/components/ui/spinner';
import { useTheme } from '@/hooks/shared/use-theme';
import { useTranslator } from '@/hooks/shared/use-translator';
import { useGateKeeperContext } from '@/providers/gate-keeper-context';

interface GateKeeperProps {
  styling?: ComponentStyling<Record<string, string>>;
  isLoading?: boolean;
  children: React.ReactNode;
}

/**
 * Blocking error fallback with retry button.
 * Shown for 5xx errors and dismissed MFA errors.
 *
 * @param props - Component props.
 * @param props.onRetry - Retry handler.
 * @returns Error fallback element.
 * @internal
 */
function ErrorFallback({ onRetry }: { onRetry: () => void }) {
  const { t } = useTranslator('gate_keeper');

  return (
    <Card className="text-center">
      <CardContent className="flex flex-col items-center gap-2">
        <CardTitle>{t('fallback.title')}</CardTitle>
        <CardDescription>{t('fallback.description')}</CardDescription>
      </CardContent>
      <CardFooter className="justify-center">
        <Button variant="primary" size="default" onClick={onRetry}>
          <RefreshCcw className="size-4" />
          {t('fallback.retry')}
        </Button>
      </CardFooter>
    </Card>
  );
}

/**
 * MFA step-up dialog.
 *
 * @param props - Component props.
 * @param props.error - MFA error containing the token and challenge details.
 * @param props.onComplete - Callback when MFA is completed successfully; triggers a retry.
 * @param props.onClose - Callback when the dialog is dismissed without completing.
 * @returns MFA dialog element.
 * @internal
 */
function MfaDialog({
  error,
  onComplete,
  onClose,
}: {
  error: MfaRequiredError;
  onComplete: () => void;
  onClose: () => void;
}) {
  return (
    <Dialog open onOpenChange={(open) => !open && onClose()}>
      <DialogContent>
        <MfaWizard error={error} onComplete={onComplete} onCancel={onClose} />
      </DialogContent>
    </Dialog>
  );
}

/**
 * Guards children from rendering during loading/error states. MFA step-up overlays
 * children without unmounting them, preserving any in-progress form state.
 * - Loading → spinner (blocks children)
 * - MFA required error → MFA step-up dialog overlaid on children
 * - 5xx error or dismissed MFA → blocking error fallback with retry
 * - No error → children
 *
 * @param props - Component props.
 * @param props.styling - Styling configuration forwarded to the styled scope.
 * @param props.isLoading - Whether content is loading.
 * @param props.children - Child elements to render on success.
 * @returns GateKeeper element.
 */
export function GateKeeper({ styling, isLoading, children }: GateKeeperProps) {
  const { error, onRetry } = useGateKeeperContext();
  const { isDarkMode } = useTheme();
  const [isRetrying, setIsRetrying] = useState(false);
  const [dismissedMfaToken, setDismissedMfaToken] = useState<string | null>(null);

  const styles = useMemo(() => getComponentStyles(styling, isDarkMode), [styling, isDarkMode]);

  const handleRetry = useCallback(async () => {
    setIsRetrying(true);
    setDismissedMfaToken(null);
    try {
      await onRetry?.();
    } finally {
      setIsRetrying(false);
    }
  }, [onRetry]);

  const isMfaStepUp = isMfaRequiredError(error);
  const mfaError = isMfaStepUp ? normalizeMfaRequiredError(error) : null;
  const isMfaDismissed = dismissedMfaToken === mfaError?.mfa_token;
  const statusCode = getStatusCode(error);
  const isSystemError = !!error && !!statusCode && statusCode >= 500;

  if (isLoading || isRetrying) {
    return (
      <StyledScope style={styles.variables}>
        <div className="flex items-center justify-center p-8">
          <Spinner />
        </div>
      </StyledScope>
    );
  }

  if (isSystemError || (isMfaStepUp && isMfaDismissed)) {
    return (
      <StyledScope style={styles.variables}>
        <ErrorFallback onRetry={handleRetry} />
      </StyledScope>
    );
  }

  return (
    <StyledScope style={styles.variables}>
      {children}
      {mfaError && !isMfaDismissed && (
        <MfaDialog
          error={mfaError}
          onComplete={handleRetry}
          onClose={() => setDismissedMfaToken(mfaError.mfa_token)}
        />
      )}
    </StyledScope>
  );
}

/** @internal */
import {
  normalizeFactorType,
  type EnrollmentFactor,
  type MfaAuthenticator,
  type MfaRequiredError,
} from '@auth0/universal-components-core';
import { useState } from 'react';

import { Button } from '@/components/ui/button';
import { Card, CardAction, CardHeader, CardTitle } from '@/components/ui/card';
import { List, ListItem } from '@/components/ui/list';
import { Separator } from '@/components/ui/separator';
import { Spinner } from '@/components/ui/spinner';
import { useMfaRequirements } from '@/hooks/shared/use-mfa-requirements';
import { useTranslator } from '@/hooks/shared/use-translator';

interface AuthenticatorsListProps {
  error: MfaRequiredError;
  onSelectFactor: (factor: EnrollmentFactor) => void;
  onSelectAuthenticator: (authenticator: MfaAuthenticator) => void;
  onCancel: () => void;
}

/**
 * @param props - Component props.
 * @param props.error - The MFA required error.
 * @param props.onSelectFactor - Called when the user picks a factor to enroll.
 * @param props.onSelectAuthenticator - Called when the user picks an authenticator to challenge.
 * @param props.onCancel - Called when the user cancels.
 * @returns Authenticator list element, spinner during load, or null.
 * @internal
 */
export function AuthenticatorsList({
  error,
  onSelectFactor,
  onSelectAuthenticator,
  onCancel,
}: AuthenticatorsListProps) {
  const { t } = useTranslator('gate_keeper');
  const [activeItemId, setActiveItemId] = useState<string | null>(null);

  const { factors, authenticators, isEnrollMode, isLoading } = useMfaRequirements(error);

  const handleSelectFactor = (factor: EnrollmentFactor) => {
    setActiveItemId(factor.type);
    onSelectFactor(factor);
  };

  const handleSelectAuthenticator = (auth: MfaAuthenticator) => {
    setActiveItemId(auth.id);
    onSelectAuthenticator(auth);
  };

  const items = isEnrollMode
    ? factors.map((factor) => ({
        key: factor.type,
        label: t(`mfa.authenticator_type.${normalizeFactorType(factor.type)}`),
        buttonLabel: t('mfa.enroll_button'),
        onSelect: () => handleSelectFactor(factor),
      }))
    : authenticators.map((auth) => ({
        key: auth.id,
        label: auth.type
          ? t(`mfa.authenticator_type.${normalizeFactorType(auth.type)}`)
          : auth.name,
        buttonLabel: t('mfa.verify_button'),
        onSelect: () => handleSelectAuthenticator(auth),
      }));

  if (isLoading) {
    return (
      <div className="flex items-center justify-center p-8">
        <Spinner />
      </div>
    );
  }

  if (!items.length) {
    return (
      <div className="space-y-6">
        <p className="text-sm text-muted-foreground">{t('mfa.no_authenticators')}</p>
        <Separator />
        <div className="flex justify-end">
          <Button variant="outline" onClick={onCancel} aria-label={t('mfa.cancel')}>
            {t('mfa.cancel')}
          </Button>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <List className="flex flex-col gap-3">
        {items.map((item) => (
          <ListItem key={item.key} aria-label={item.label}>
            <Card>
              <CardHeader>
                <CardTitle className="text-base font-semibold text-left">{item.label}</CardTitle>
                <CardAction>
                  <Button
                    variant="primary"
                    onClick={item.onSelect}
                    disabled={activeItemId !== null}
                    aria-label={`${item.buttonLabel} ${item.label}`}
                  >
                    {activeItemId === item.key ? (
                      <Spinner size="sm" colorScheme="foreground" />
                    ) : (
                      item.buttonLabel
                    )}
                  </Button>
                </CardAction>
              </CardHeader>
            </Card>
          </ListItem>
        ))}
      </List>
      <Separator />
      <div className="flex justify-end">
        <Button
          variant="outline"
          onClick={onCancel}
          disabled={activeItemId !== null}
          aria-label={t('mfa.cancel')}
        >
          {t('mfa.cancel')}
        </Button>
      </div>
    </div>
  );
}

/**
 * MFA enrollment setup form.
 * @module enrollment-form
 * @internal
 */

import {
  FACTOR_TYPE_EMAIL,
  FACTOR_TYPE_OTP,
  FACTOR_TYPE_PUSH,
  FACTOR_TYPE_SMS,
  FACTOR_TYPE_VOICE,
  createEmailContactSchema,
  createSmsContactSchema,
  type EmailContactForm,
  type EnrollmentFactor,
  type EnrollmentResponse,
  type EnrollParams,
  type MfaRequiredError,
  type SmsContactForm,
} from '@auth0/universal-components-core';
import { zodResolver } from '@hookform/resolvers/zod';
import { useCallback, useEffect, useMemo, useState } from 'react';
import { useForm } from 'react-hook-form';

import { VerifyForm } from './verify-form';

import AppleLogo from '@/assets/icons/apple-logo';
import GoogleLogo from '@/assets/icons/google-logo';
import { CopyableTextField } from '@/components/auth0/shared/copyable-text-field';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Checkbox } from '@/components/ui/checkbox';
import { DialogDescription, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { Label } from '@/components/ui/label';
import { QRCodeDisplayer } from '@/components/ui/qr-code';
import { Separator } from '@/components/ui/separator';
import { Spinner } from '@/components/ui/spinner';
import { TextField } from '@/components/ui/text-field';
import { useMfaStepUp } from '@/hooks/shared/use-mfa-step-up';
import { useTranslator } from '@/hooks/shared/use-translator';

interface EnrollmentFormProps {
  error: MfaRequiredError;
  factor: EnrollmentFactor;
  onComplete: () => void;
  onCancel: () => void;
}

const GUARDIAN_APP_STORE_URL = 'https://apps.apple.com/us/app/auth0-guardian/id1093447833';
const GUARDIAN_PLAY_STORE_URL = 'https://play.google.com/store/apps/details?id=com.auth0.guardian';

const FACTOR_INITIAL_STEP: Record<string, EnrollStep> = {
  [FACTOR_TYPE_OTP]: 'qr',
  [FACTOR_TYPE_PUSH]: 'install',
};

type EnrollStep = 'install' | 'input' | 'qr' | 'verify' | 'recovery';
type ContactForm = EmailContactForm | SmsContactForm;

/**
 * Multi-step enrollment form for MFA step-up. Supports OTP, Push, SMS, Voice, and Email factors.
 * Recovery codes are shown on first enrollment of any factor.
 *
 * @param props - Component props.
 * @returns Enrollment form element.
 * @internal
 */
export function EnrollmentForm({ error, factor, onComplete, onCancel }: EnrollmentFormProps) {
  const { t } = useTranslator('gate_keeper');

  const mfaToken = error.mfa_token;

  const isOtp = factor.type === FACTOR_TYPE_OTP;
  const isPush = factor.type === FACTOR_TYPE_PUSH;

  const [step, setStep] = useState<EnrollStep>(FACTOR_INITIAL_STEP[factor.type] ?? 'input');
  const [enrollResponse, setEnrollResponse] = useState<EnrollmentResponse | undefined>();
  const [recoveryConfirmed, setRecoveryConfirmed] = useState(false);

  const handleVerifyComplete = useCallback(() => {
    if (enrollResponse?.recoveryCodes?.length) {
      setStep('recovery');
    } else {
      onComplete();
    }
  }, [enrollResponse, onComplete]);

  const { enroll, isLoading } = useMfaStepUp({ error, onComplete: handleVerifyComplete });

  const contactSchema = useMemo(
    () =>
      factor.type === FACTOR_TYPE_EMAIL
        ? createEmailContactSchema(t('mfa.enroll.invalid_email'))
        : createSmsContactSchema(t('mfa.enroll.invalid_phone_number')),
    [factor.type, t],
  );

  const inputForm = useForm<ContactForm>({
    resolver: zodResolver(contactSchema),
    mode: 'onChange',
  });

  // OTP only: call enroll on mount then show QR.
  useEffect(() => {
    if (!isOtp) return;

    const initialiseOtpEnrollment = async () => {
      const response = await enroll({ mfaToken, factorType: FACTOR_TYPE_OTP });
      if (response) setEnrollResponse(response);
    };

    initialiseOtpEnrollment();
  }, [enroll, isOtp, mfaToken]);

  const handleInputSubmit = async ({ contact }: ContactForm) => {
    const params: EnrollParams =
      factor.type === FACTOR_TYPE_EMAIL
        ? { mfaToken, factorType: FACTOR_TYPE_EMAIL, email: contact }
        : { mfaToken, factorType: factor.type as 'sms' | 'voice', phoneNumber: contact };

    const response = await enroll(params);

    if (response) {
      setEnrollResponse(response);
      setStep('verify');
    }
  };

  const handlePushEnroll = async () => {
    const response = await enroll({ mfaToken, factorType: FACTOR_TYPE_PUSH });
    if (!response) return;
    setEnrollResponse(response);
    setStep('qr');
  };

  if (isOtp && !enrollResponse && step === 'qr') {
    return (
      <div className="flex items-center justify-center p-8" role="status" aria-live="polite">
        <Spinner />
      </div>
    );
  }

  if (step === 'install') {
    return (
      <>
        <DialogHeader>
          <DialogTitle>{t('mfa.enroll.install_title')}</DialogTitle>
          <DialogDescription>{t('mfa.enroll.install_description')}</DialogDescription>
        </DialogHeader>
        <Separator />

        <div className="flex gap-4 my-4">
          <a
            href={GUARDIAN_APP_STORE_URL}
            target="_blank"
            rel="noopener noreferrer"
            className="flex-1"
          >
            <Card className="flex flex-col items-center gap-2 p-4 h-full">
              <AppleLogo className="w-8 h-8" />
              <span className="text-sm text-center">{t('mfa.enroll.app_store')}</span>
            </Card>
          </a>
          <a
            href={GUARDIAN_PLAY_STORE_URL}
            target="_blank"
            rel="noopener noreferrer"
            className="flex-1"
          >
            <Card className="flex flex-col items-center gap-2 p-4 h-full">
              <GoogleLogo className="w-8 h-8" />
              <span className="text-sm text-center">{t('mfa.enroll.google_play')}</span>
            </Card>
          </a>
        </div>

        <Separator />

        <div className="flex justify-end gap-3 mt-4">
          <Button
            type="button"
            variant="outline"
            onClick={onCancel}
            disabled={isLoading}
            aria-label={t('mfa.back')}
          >
            {t('mfa.back')}
          </Button>
          <Button
            type="button"
            variant="primary"
            onClick={handlePushEnroll}
            disabled={isLoading}
            aria-label={t('mfa.continue')}
          >
            {isLoading && <Spinner size="sm" colorScheme="foreground" />}
            {t('mfa.continue')}
          </Button>
        </div>
      </>
    );
  }

  if (step === 'verify' && enrollResponse) {
    return (
      <VerifyForm
        error={error}
        authenticator={{ ...enrollResponse, name: inputForm.getValues('contact') }}
        onComplete={handleVerifyComplete}
        onCancel={() => setStep(isOtp ? 'qr' : 'input')}
      />
    );
  }

  if (step === 'input') {
    const inputConfig =
      factor.type === FACTOR_TYPE_SMS || factor.type === FACTOR_TYPE_VOICE
        ? {
            label: t('mfa.enroll.phone_label'),
            description: t('mfa.enroll.phone_description'),
            title: t('mfa.enroll.phone_title'),
            placeholder: '+1 555 000 0000',
            type: 'tel',
            autoComplete: 'tel',
          }
        : {
            label: t('mfa.enroll.email_label'),
            description: t('mfa.enroll.email_description'),
            title: t('mfa.enroll.email_title'),
            placeholder: 'you@example.com',
            type: 'email',
            autoComplete: 'email',
          };

    return (
      <>
        <DialogHeader>
          <DialogTitle>{inputConfig.title}</DialogTitle>
        </DialogHeader>
        <Separator />
        <Form {...inputForm}>
          <form onSubmit={inputForm.handleSubmit(handleInputSubmit)} className="space-y-6">
            <FormField
              control={inputForm.control}
              name="contact"
              render={({ field }) => (
                <FormItem>
                  <FormLabel
                    htmlFor="enroll-input"
                    className="text-left text-sm text-(length:--font-size-paragraph) font-medium"
                  >
                    {inputConfig.label}
                  </FormLabel>
                  <FormControl>
                    <TextField
                      id="enroll-input"
                      {...field}
                      type={inputConfig.type}
                      placeholder={inputConfig.placeholder}
                      autoComplete={inputConfig.autoComplete}
                    />
                  </FormControl>
                  <FormDescription className="text-sm text-(length:--font-size-paragraph) font-normal text-left">
                    {inputConfig.description}
                  </FormDescription>
                  <FormMessage
                    className="text-left text-sm text-(length:--font-size-paragraph)"
                    id="contact-error"
                    role="alert"
                  />
                </FormItem>
              )}
            />

            <Separator />

            <div className="flex justify-end gap-3">
              <Button
                type="button"
                variant="outline"
                onClick={onCancel}
                disabled={isLoading}
                aria-label={t('mfa.back')}
              >
                {t('mfa.back')}
              </Button>
              <Button
                type="submit"
                variant="primary"
                disabled={!inputForm.formState.isValid || isLoading}
                aria-label={isLoading ? t('mfa.enroll.enrolling') : t('mfa.verify_button')}
              >
                {isLoading && <Spinner size="sm" colorScheme="foreground" />}
                {isLoading ? t('mfa.enroll.enrolling') : t('mfa.verify_button')}
              </Button>
            </div>
          </form>
        </Form>
      </>
    );
  }

  if (step === 'qr' && enrollResponse?.barcodeUri) {
    const barcodeUri = enrollResponse.barcodeUri;
    const description = isPush
      ? t('mfa.enroll.push_scan_description')
      : t('mfa.enroll.scan_description');
    return (
      <>
        <DialogHeader>
          <DialogTitle>{t('mfa.title')}</DialogTitle>
        </DialogHeader>
        <Separator />
        <div className="flex justify-center my-4">
          <QRCodeDisplayer size={160} value={barcodeUri} alt={t('mfa.enroll.qr_alt')} />
        </div>

        <div className="space-y-4" aria-describedby="qr-description">
          <p
            id="qr-description"
            className="font-semibold text-base text-center text-(length:--font-size-paragraph) text-primary"
          >
            {description}
          </p>

          {!isPush && (
            <p className="font-normal text-sm text-(length:--font-size-paragraph)">
              {t('mfa.enroll.scan_helper')}
            </p>
          )}

          {enrollResponse.authenticatorType === FACTOR_TYPE_OTP && (
            <CopyableTextField value={enrollResponse.secret} />
          )}
        </div>

        <Separator className="mt-4" />

        <div className="flex justify-end gap-3 mt-4">
          <Button
            type="button"
            variant="outline"
            onClick={isPush ? () => setStep('install') : onCancel}
            disabled={isLoading}
            aria-label={t('mfa.back')}
          >
            {t('mfa.back')}
          </Button>
          <Button
            type="button"
            variant="primary"
            onClick={() => (isOtp ? setStep('verify') : handleVerifyComplete())}
            disabled={isLoading}
            aria-label={t('mfa.continue')}
          >
            {isLoading && <Spinner size="sm" colorScheme="foreground" />}
            {t('mfa.continue')}
          </Button>
        </div>
      </>
    );
  }

  return (
    <>
      <DialogHeader>
        <DialogTitle>{t('mfa.enroll.recovery_title')}</DialogTitle>
        <DialogDescription>{t('mfa.enroll.recovery_description')}</DialogDescription>
      </DialogHeader>
      <Separator />
      <div className="space-y-4 my-6">
        {enrollResponse?.recoveryCodes?.[0] && (
          <CopyableTextField value={enrollResponse.recoveryCodes[0]} />
        )}

        <div className="flex items-center gap-3">
          <Checkbox
            id="recovery-confirmed"
            checked={recoveryConfirmed}
            onCheckedChange={(checked) => setRecoveryConfirmed(checked === true)}
          />
          <Label htmlFor="recovery-confirmed" className="cursor-pointer">
            {t('mfa.enroll.recovery_confirmed')}
          </Label>
        </div>
      </div>

      <Separator />

      <div className="flex justify-end gap-3 mt-4">
        <Button
          type="button"
          variant="primary"
          onClick={onComplete}
          disabled={!recoveryConfirmed}
          aria-label={t('mfa.continue')}
        >
          {t('mfa.continue')}
        </Button>
      </div>
    </>
  );
}

/**
 * MFA wizard orchestrator.
 * @module mfa-wizard
 * @internal
 */
import {
  normalizeFactorType,
  type EnrollmentFactor,
  type MfaAuthenticator,
  type MfaRequiredError,
} from '@auth0/universal-components-core';
import { useState } from 'react';

import { AuthenticatorsList } from './authenticators-list';
import { EnrollmentForm } from './enrollment-form';
import { VerifyForm } from './verify-form';

import { DialogDescription, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Separator } from '@/components/ui/separator';
import { useTranslator } from '@/hooks/shared/use-translator';

type MfaWizardState =
  | { view: 'list' }
  | { view: 'enroll'; factor: EnrollmentFactor }
  | { view: 'challenge'; authenticator: MfaAuthenticator };

interface MfaWizardProps {
  error: MfaRequiredError;
  onComplete: () => void;
  onCancel: () => void;
}

/**
 * Orchestrates the MFA step-up flow: list → enroll or challenge → complete.
 *
 * @param props - Component props.
 * @param props.error - The MFA required error from the step-up flow.
 * @param props.onComplete - Called after successful challenge or enrollment.
 * @param props.onCancel - Called when the user cancels the flow.
 * @returns MFA wizard element.
 * @internal
 */
export function MfaWizard({ error, onComplete, onCancel }: MfaWizardProps) {
  const { t } = useTranslator('gate_keeper');
  const [state, setState] = useState<MfaWizardState>({ view: 'list' });

  const handleSelectFactor = (factor: EnrollmentFactor) =>
    setState({ view: 'enroll', factor: { ...factor, type: normalizeFactorType(factor.type) } });

  const handleSelectAuthenticator = (authenticator: MfaAuthenticator) =>
    setState({ view: 'challenge', authenticator });

  if (state.view === 'enroll') {
    return (
      <EnrollmentForm
        error={error}
        factor={state.factor}
        onComplete={onComplete}
        onCancel={() => setState({ view: 'list' })}
      />
    );
  }

  if (state.view === 'challenge') {
    return (
      <VerifyForm
        error={error}
        authenticator={state.authenticator}
        onComplete={onComplete}
        onCancel={() => setState({ view: 'list' })}
      />
    );
  }

  return (
    <>
      <DialogHeader>
        <DialogTitle>{t('mfa.title')}</DialogTitle>
        <DialogDescription>{t('mfa.subtitle')}</DialogDescription>
      </DialogHeader>
      <Separator />
      <AuthenticatorsList
        error={error}
        onSelectFactor={handleSelectFactor}
        onSelectAuthenticator={handleSelectAuthenticator}
        onCancel={onCancel}
      />
    </>
  );
}

/** @internal */

import { FACTOR_TYPE_RECOVERY_CODE } from '@auth0/universal-components-core';
import { useEffect, useRef, useState } from 'react';
import { useForm } from 'react-hook-form';

import { Button } from '@/components/ui/button';
import { Form, FormControl, FormField, FormItem, FormMessage } from '@/components/ui/form';
import { Link } from '@/components/ui/link';
import { OTPField } from '@/components/ui/otp-field';
import { Separator } from '@/components/ui/separator';
import { Spinner } from '@/components/ui/spinner';
import { TextField } from '@/components/ui/text-field';
import { useTranslator } from '@/hooks/shared/use-translator';

interface Authenticator {
  authenticatorType?: string;
  name?: string;
}

interface OtpCodeFormProps {
  onSubmit: (code: string) => Promise<void>;
  onCancel: () => void;
  isLoading: boolean;
  authenticator?: Authenticator;
  onResend?: () => Promise<void>;
}

type CodeForm = { code: string };

/**
 * OTP / recovery-code input form for MFA step-up.
 *
 * Renders a 6-digit OTP field or a plain text field for recovery codes, with
 * Cancel and Verify buttons. Owns its own form state and auto-focuses on mount.
 *
 * @param props - Component props.
 * @param props.onSubmit - Called with the entered code on form submission.
 * @param props.onCancel - Called when the user cancels.
 * @param props.isLoading - Whether a verification request is in flight.
 * @returns Code input form element.
 * @internal
 */
export function OtpCodeForm({
  onSubmit,
  onCancel,
  isLoading,
  authenticator,
  onResend,
}: OtpCodeFormProps) {
  const { t } = useTranslator('gate_keeper');

  const [isResending, setIsResending] = useState(false);

  const isRecoveryCode = authenticator?.authenticatorType === FACTOR_TYPE_RECOVERY_CODE;

  const form = useForm<CodeForm>({ mode: 'onChange' });
  const code = form.watch('code');
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleResend = async () => {
    setIsResending(true);
    await onResend?.();
    form.reset();
    setIsResending(false);
  };

  const submitLabel = isLoading ? t('mfa.challenge.verifying') : t('mfa.verify_button');

  const description = authenticator?.name
    ? t('mfa.challenge.code_sent_description', { name: authenticator.name })
    : isRecoveryCode
      ? t('mfa.challenge.recovery_code_description')
      : t('mfa.challenge.otp_description');

  return (
    <Form {...form}>
      <form
        onSubmit={form.handleSubmit(({ code: enteredCode }) => onSubmit(enteredCode))}
        autoComplete="off"
        className="space-y-6"
      >
        <div className="space-y-4">
          {authenticator && (
            <p className="text-sm text-(length:--font-size-paragraph)">{description}</p>
          )}
          <FormField
            control={form.control}
            name="code"
            render={({ field }) => (
              <FormItem>
                <FormControl>
                  {isRecoveryCode ? (
                    <TextField
                      id="step-up-code"
                      {...field}
                      value={field.value || ''}
                      placeholder="XHPOWIHEFSDO23435pwe"
                      autoComplete="off"
                      ref={inputRef}
                    />
                  ) : (
                    <OTPField
                      id="step-up-code"
                      length={6}
                      separator={{ character: '-', afterEvery: 3 }}
                      onChange={field.onChange}
                      inputRef={inputRef}
                      value={field.value || ''}
                    />
                  )}
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />
          {onResend && (
            <p className="text-sm text-muted-foreground text-center">
              {t('mfa.challenge.resend_prompt')}
              <Link onClick={handleResend} aria-disabled={isResending} className="text-sm ms-1">
                {t('mfa.challenge.resend')}
              </Link>
            </p>
          )}
        </div>

        <Separator />

        <div className="flex justify-end gap-3">
          <Button
            type="button"
            variant="outline"
            onClick={onCancel}
            disabled={isLoading}
            aria-label={t('mfa.back')}
          >
            {t('mfa.back')}
          </Button>
          <Button
            type="submit"
            variant="primary"
            disabled={(isRecoveryCode ? !code : code?.length !== 6) || isLoading}
            aria-label={submitLabel}
          >
            {isLoading && <Spinner size="sm" colorScheme="foreground" />}
            {submitLabel}
          </Button>
        </div>
      </form>
    </Form>
  );
}

/**
 * MFA step-up verify form.
 * @module step-up-verify-form
 * @internal
 */

import {
  FACTOR_TYPE_PUSH_NOTIFICATION,
  FACTOR_TYPE_RECOVERY_CODE,
  type MfaRequiredError,
} from '@auth0/universal-components-core';
import { useEffect, useState } from 'react';

import { OtpCodeForm } from './otp-code-form';

import { Button } from '@/components/ui/button';
import { DialogDescription, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Separator } from '@/components/ui/separator';
import { Spinner } from '@/components/ui/spinner';
import { useMfaStepUp } from '@/hooks/shared/use-mfa-step-up';
import { useTranslator } from '@/hooks/shared/use-translator';

interface VerifyAuthenticator {
  id?: string;
  authenticatorType: 'otp' | 'oob' | 'recovery-code';
  oobCode?: string;
  type?: string;
  name?: string;
}

interface VerifyFormProps {
  error: MfaRequiredError;
  authenticator: VerifyAuthenticator;
  onComplete: () => void;
  onCancel: () => void;
}

/**
 * Verify form for MFA step-up. Handles OTP, OOB (SMS, email, push, voice), and recovery-code authenticators.
 *
 * @param props - Component props.
 * @returns Verify form element.
 * @internal
 */
export function VerifyForm({ error, authenticator, onComplete, onCancel }: VerifyFormProps) {
  const { t } = useTranslator('gate_keeper');
  const { challenge, verify, isLoading } = useMfaStepUp({ error, onComplete });
  const mfaToken = error.mfa_token;

  const isOob = authenticator.authenticatorType === 'oob';
  const isRecoveryCode = authenticator.authenticatorType === FACTOR_TYPE_RECOVERY_CODE;
  const isPush = authenticator.type === FACTOR_TYPE_PUSH_NOTIFICATION;

  const [challenged, setChallenged] = useState(!isOob || !!authenticator.oobCode);
  const [oobCode, setOobCode] = useState<string | undefined>(authenticator.oobCode);

  const handleVerify = async (code: string) => {
    if (isOob) await verify({ mfaToken, oobCode, bindingCode: code });
    else if (isRecoveryCode) await verify({ mfaToken, recoveryCode: code });
    else await verify({ mfaToken, otp: code });
  };

  const handleResend = async () => {
    const response = await challenge(authenticator);
    if (response?.oobCode) setOobCode(response.oobCode);
  };

  useEffect(() => {
    if (!isOob || authenticator.oobCode) return;

    const initializeChallenge = async () => {
      const response = await challenge(authenticator);
      if (response?.oobCode) {
        setOobCode(response.oobCode);
        setChallenged(true);
      }
    };

    initializeChallenge();
  }, [isOob, challenge, authenticator.id, authenticator.oobCode]);

  if (!challenged) {
    return (
      <div className="flex items-center justify-center p-8" role="status" aria-live="polite">
        <Spinner />
      </div>
    );
  }

  if (isPush) {
    return (
      <>
        <DialogHeader>
          <DialogTitle>{t('mfa.challenge.push_title')}</DialogTitle>
          <DialogDescription>{t('mfa.challenge.push_description')}</DialogDescription>
        </DialogHeader>

        <p className="text-center text-sm text-(length:--font-size-paragraph) font-normal my-4">
          {t('mfa.challenge.push_waiting')}
        </p>

        <Separator />

        <div className="flex justify-end gap-3">
          <Button type="button" variant="outline" onClick={onCancel} aria-label={t('mfa.cancel')}>
            {t('mfa.cancel')}
          </Button>
          <Button
            type="button"
            variant="primary"
            onClick={onComplete}
            aria-label={t('mfa.continue')}
          >
            {t('mfa.continue')}
          </Button>
        </div>
      </>
    );
  }

  return (
    <>
      <DialogHeader>
        <DialogTitle>{t('mfa.title')}</DialogTitle>
      </DialogHeader>
      <Separator />
      <OtpCodeForm
        onSubmit={handleVerify}
        onCancel={onCancel}
        isLoading={isLoading}
        authenticator={authenticator}
        onResend={isOob && !isPush ? handleResend : undefined}
      />
    </>
  );
}

/**
 * Section header with actions.
 * @module header
 * @internal
 */

import type { ActionButton as CoreActionButton } from '@auth0/universal-components-core';
import type { LucideIcon } from 'lucide-react';
import { ArrowLeft } from 'lucide-react';
import * as React from 'react';

import { Button } from '@/components/ui/button';
import { Spinner } from '@/components/ui/spinner';
import { Switch } from '@/components/ui/switch';
import { Tooltip, TooltipTrigger, TooltipContent } from '@/components/ui/tooltip';
import { cn } from '@/lib/utils';

export interface TooltipProps {
  content: React.ReactNode | string;
}

export interface WithTooltipProps {
  trigger: React.ReactNode | string;
  tooltip: TooltipProps;
}

export interface BaseActionProps extends Omit<CoreActionButton, 'icon' | 'onClick'> {
  icon?: LucideIcon;
  className?: string;
  hidden?: boolean;
  tooltip?: TooltipProps;
}

export interface ButtonActionProps extends BaseActionProps {
  type: 'button';
  onClick: (e: React.MouseEvent<HTMLButtonElement>) => void;
}

export interface SwitchActionProps extends Omit<BaseActionProps, 'type' | 'label'> {
  type: 'switch';
  checked?: boolean;
  onCheckedChange: (checked: boolean) => void;
  'aria-label'?: string;
}

export type ActionProps = ButtonActionProps | SwitchActionProps;

export interface HeaderProps {
  title?: string;
  description?: string;
  backButton?: {
    text?: string;
    icon?: LucideIcon;
    onClick: (e: React.MouseEvent<HTMLButtonElement>) => void;
  };
  actions?: ActionProps[];
  isLoading?: boolean;
  className?: string;
}

const WithTooltip: React.FC<WithTooltipProps> = ({ trigger, tooltip }) => (
  <>
    <Tooltip>
      <TooltipTrigger asChild>
        <div>{trigger}</div>
      </TooltipTrigger>
      <TooltipContent>{tooltip.content}</TooltipContent>
    </Tooltip>
  </>
);

const ButtonAction: React.FC<ButtonActionProps> = ({
  icon: Icon,
  className,
  label,
  onClick,
  disabled,
  variant,
  size,
}) => (
  <Button
    onClick={onClick}
    disabled={disabled}
    variant={variant}
    size={size}
    className={cn('flex items-center gap-2 w-full sm:w-auto sm:min-w-fit', className)}
    aria-label={label}
  >
    {Icon && <Icon className="h-4 w-4 flex-shrink-0" aria-hidden="true" />}
    <span className="truncate">{label}</span>
  </Button>
);

const SwitchAction: React.FC<SwitchActionProps> = ({
  className,
  'aria-label': ariaLabel,
  checked,
  onCheckedChange,
  disabled,
}) => (
  <div className={cn('flex items-center gap-2', className)}>
    <Switch
      checked={checked}
      onCheckedChange={onCheckedChange}
      disabled={disabled}
      aria-label={ariaLabel}
    />
  </div>
);

export const Header = React.forwardRef<
  HTMLDivElement,
  HeaderProps & React.HTMLAttributes<HTMLDivElement>
>(({ title, description, backButton, actions, isLoading, className, ...props }, ref) => {
  const BackIcon = backButton?.icon || ArrowLeft;

  const renderAction = (action: ActionProps, index: number) => {
    const key = `action-${index}`;
    if (isLoading) {
      return <Spinner key={`spinner-${key}`} className="w-4 h-4" />;
    }
    if (action.hidden) {
      return null;
    }
    const actionElement =
      action.type === 'switch' ? (
        <SwitchAction key={key} {...action} />
      ) : (
        <ButtonAction key={key} {...action} />
      );
    if (action.tooltip) {
      return (
        <WithTooltip key={`tooltip-${key}`} trigger={actionElement} tooltip={action.tooltip} />
      );
    }
    return actionElement;
  };

  return (
    <div
      ref={ref}
      className={cn('w-full mb-8', className)}
      role="banner"
      aria-label={title ? `${title} header` : 'Header'}
      {...props}
    >
      {backButton && (
        <Button
          variant="link"
          onClick={backButton.onClick}
          size="default"
          className="flex items-center text-sm mb-3"
          aria-label={backButton.text || 'Go back'}
        >
          <BackIcon className="h-4 w-4" aria-hidden="true" />
          {backButton.text && <span>{backButton.text}</span>}
        </Button>
      )}

      <div className="flex items-start justify-between gap-4">
        <div className="flex flex-col min-w-0 flex-1">
          {title && (
            <h1
              className={cn(
                'text-xl sm:text-2xl text-primary md:text-4xl font-bold leading-tight break-words text-left text-(length:--font-size-page-header) mb-0',
              )}
            >
              {title}
            </h1>
          )}
          {description && (
            <p
              className={cn(
                'text-base text-muted-foreground leading-relaxed break-words text-left text-(length:--font-size-page-description) mt-2',
              )}
            >
              {description}
            </p>
          )}
        </div>

        {actions && actions.length > 0 && (
          <div className="flex-shrink-0 flex items-start gap-2 mt-1">
            {actions.map(renderAction)}
          </div>
        )}
      </div>
    </div>
  );
});

Header.displayName = 'Header';

/**
 * Section layout with title and actions.
 * @module section
 * @internal
 */

import type { ActionButton as CoreActionButton } from '@auth0/universal-components-core';
import type { LucideIcon } from 'lucide-react';
import * as React from 'react';

import { Button } from '@/components/ui/button';
import { Toggle } from '@/components/ui/toggle';
import { cn } from '@/lib/utils';

export interface BaseActionProps extends Omit<CoreActionButton, 'icon' | 'onClick'> {
  icon?: LucideIcon;
  className?: string;
}

export interface ButtonActionProps extends BaseActionProps {
  type: 'button';
  onClick: (e: React.MouseEvent<HTMLButtonElement>) => void;
}

export interface ToggleActionProps extends Omit<BaseActionProps, 'type'> {
  type: 'toggle';
  pressed?: boolean;
  onPressedChange: (pressed: boolean) => void;
  'aria-label': string;
}

export type ActionProps = ButtonActionProps | ToggleActionProps;

interface SectionProps {
  title?: string;
  description?: string;
  children: React.ReactNode;
  actions?: ActionProps[];
  className?: string;
}

const ButtonAction: React.FC<ButtonActionProps> = ({
  icon: Icon,
  className,
  label,
  onClick,
  disabled,
  variant,
  size,
}) => (
  <Button
    onClick={onClick}
    disabled={disabled}
    variant={variant}
    size={size}
    className={cn('flex items-center gap-2 w-full sm:w-auto sm:min-w-fit', className)}
    aria-label={label}
  >
    {Icon && <Icon className="h-4 w-4 flex-shrink-0" aria-hidden="true" />}
    <span className="truncate">{label}</span>
  </Button>
);

const ToggleAction: React.FC<ToggleActionProps> = ({
  icon: Icon,
  className,
  label,
  'aria-label': ariaLabel,
  pressed,
  onPressedChange,
  disabled,
  variant,
  size,
}) => (
  <Toggle
    pressed={pressed}
    onPressedChange={onPressedChange}
    disabled={disabled}
    variant={variant === 'outline' ? 'outline' : 'default'}
    size={size === 'icon' || size === 'xs' ? 'sm' : size}
    className={cn('flex items-center gap-2', className)}
    aria-label={ariaLabel}
  >
    {Icon && <Icon className="h-4 w-4 flex-shrink-0" aria-hidden="true" />}
    {label && <span className="truncate">{label}</span>}
  </Toggle>
);

/**
 *
 * @param props - Component props.
 * @param props.title - The title text
 * @param props.description - The description text
 * @param props.children - Child elements to render
 * @param props.actions - Action buttons or elements
 * @param props.className - Optional CSS class name for styling
 * @returns JSX element
 */
export function Section({
  title,
  description,
  children,
  actions,
  className,
}: SectionProps): React.JSX.Element {
  const renderAction = (action: ActionProps, index: number) => {
    const key = `action-${index}`;
    return action.type === 'toggle' ? (
      <ToggleAction key={key} {...action} />
    ) : (
      <ButtonAction key={key} {...action} />
    );
  };

  return (
    <div className={cn('space-y-6', className)}>
      <div className="flex items-start justify-between gap-4">
        <div className="flex flex-col min-w-0 flex-1 space-y-2">
          {title && (
            <h3
              className={cn(
                'text-lg text-foreground text-(length:--font-size-subtitle) font-semibold mb-1 text-left',
              )}
            >
              {title}
            </h3>
          )}
          {description && (
            <p
              className={cn(
                'text-sm text-muted-foreground text-left text-(length:--font-size-paragraph)',
              )}
            >
              {description}
            </p>
          )}
        </div>

        {actions && actions.length > 0 && (
          <div className="flex-shrink-0 flex items-start gap-2 mt-1">
            {actions.map(renderAction)}
          </div>
        )}
      </div>

      <div className="space-y-6">{children}</div>
    </div>
  );
}

