/**
 * Form components with react-hook-form integration.
 * @module form
 * @internal
 */

'use client';

import type * as LabelPrimitive from '@radix-ui/react-label';
import { Slot } from '@radix-ui/react-slot';
import * as React from 'react';
import {
  Controller,
  FormProvider,
  useFormContext,
  useFormState,
  type ControllerProps,
  type FieldPath,
  type FieldValues,
} from 'react-hook-form';

import { Label } from '@/components/ui/label';
import { cn } from '@/lib/utils';

const Form: typeof FormProvider = FormProvider;

type FormFieldContextValue<
  TFieldValues extends FieldValues = FieldValues,
  TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
> = {
  name: TName;
};

const FormFieldContext = React.createContext<FormFieldContextValue>({} as FormFieldContextValue);

const FormField = <
  TFieldValues extends FieldValues = FieldValues,
  TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
>({
  ...props
}: ControllerProps<TFieldValues, TName>) => {
  return (
    <FormFieldContext.Provider value={{ name: props.name }}>
      <Controller
        {...props}
        render={({ field, fieldState, formState }) => {
          const { onChange, onBlur, ...rest } = field;
          return props.render({
            field: {
              ...rest,
              onChange: (...args: unknown[]) => {
                onChange(...(args as Parameters<typeof onChange>));
              },
              onBlur: (...args: unknown[]) => {
                onBlur(...(args as Parameters<typeof onBlur>));
              },
            },
            fieldState,
            formState,
          });
        }}
      />
    </FormFieldContext.Provider>
  );
};

const useFormField = () => {
  const fieldContext = React.useContext(FormFieldContext);
  const itemContext = React.useContext(FormItemContext);
  const { getFieldState } = useFormContext();
  const formState = useFormState({ name: fieldContext.name });
  const fieldState = getFieldState(fieldContext.name, formState);

  if (!fieldContext) {
    throw new Error('useFormField should be used within <FormField>');
  }

  const { id } = itemContext;

  return {
    id,
    name: fieldContext.name,
    formItemId: `${id}-form-item`,
    formDescriptionId: `${id}-form-item-description`,
    formMessageId: `${id}-form-item-message`,
    ...fieldState,
  };
};

type FormItemContextValue = {
  id: string;
};

const FormItemContext = React.createContext<FormItemContextValue>({} as FormItemContextValue);

function FormItem({ className, ...props }: React.ComponentProps<'div'>) {
  const id = React.useId();

  return (
    <FormItemContext.Provider value={{ id }}>
      <div data-slot="form-item" className={cn('grid gap-2', className)} {...props} />
    </FormItemContext.Provider>
  );
}

function FormLabel({ className, ...props }: React.ComponentProps<typeof LabelPrimitive.Root>) {
  const { error, formItemId } = useFormField();

  return (
    <Label
      data-slot="form-label"
      data-error={!!error}
      className={cn('data-[error=true]:text-destructive-foreground', className)}
      htmlFor={formItemId}
      {...props}
    />
  );
}

function FormControl({ ...props }: React.ComponentProps<typeof Slot>) {
  const { error, formItemId, formDescriptionId, formMessageId } = useFormField();

  return (
    <Slot
      data-slot="form-control"
      id={formItemId}
      aria-describedby={!error ? `${formDescriptionId}` : `${formDescriptionId} ${formMessageId}`}
      aria-invalid={!!error}
      {...props}
    />
  );
}

function FormDescription({ className, ...props }: React.ComponentProps<'p'>) {
  const { formDescriptionId } = useFormField();

  return (
    <p
      data-slot="form-description"
      id={formDescriptionId}
      className={cn('text-muted-foreground text-sm', className)}
      {...props}
    />
  );
}

function FormMessage({ className, ...props }: React.ComponentProps<'p'>) {
  const { error, formMessageId } = useFormField();
  const body = error ? String(error?.message ?? '') : props.children;

  if (!body) {
    return null;
  }

  return (
    <p
      data-slot="form-message"
      id={formMessageId}
      className={cn('text-destructive-foreground text-sm', className)}
      {...props}
    >
      {body}
    </p>
  );
}

export {
  useFormField,
  Form,
  FormItem,
  FormLabel,
  FormControl,
  FormDescription,
  FormMessage,
  FormField,
};

/**
 * Text field with image preview.
 * @module image-preview-field
 * @internal
 */

import { ImageIcon } from 'lucide-react';
import * as React from 'react';

import { TextField } from '@/components/ui/text-field';
import type { TextFieldProps } from '@/components/ui/text-field';
import { cn } from '@/lib/utils';

export interface ImagePreviewFieldProps extends Omit<TextFieldProps, 'onChange'> {
  previewClassName?: string;
  placeholder?: string;
  previewPlaceholder?: string;
  previewIcon?: React.ReactNode;
  imgSizes?: string;
  imgWidth?: number;
  imgHeight?: number;
  onImageLoad?: (imageUrl: string) => void;
  onImageError?: (error: Error) => void;
  onChange?: (e: React.ChangeEvent<HTMLInputElement>) => void;
}

function ImagePreviewField({
  placeholder = 'Enter image URL',
  previewPlaceholder = 'Paste an image URL to see a preview',
  previewIcon = <ImageIcon size={24} />,
  previewClassName,
  imgSizes,
  imgWidth,
  imgHeight,
  onImageLoad,
  onImageError,
  onChange,
  value,
  error,
  ...textFieldProps
}: ImagePreviewFieldProps) {
  const [imageUrl, setImageUrl] = React.useState<string>(value?.toString() || '');
  const [imageError, setImageError] = React.useState<boolean>(false);
  const [isValidUrl, setIsValidUrl] = React.useState<boolean>(true);

  const isValidImageUrl = (url: string): boolean => {
    if (!url.trim()) return true;

    try {
      const urlObj = new URL(url);
      return urlObj.protocol === 'http:' || urlObj.protocol === 'https:';
    } catch {
      return false;
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newValue = e.target.value;
    const isValid = isValidImageUrl(newValue);

    setIsValidUrl(isValid);
    setImageUrl(newValue);
    setImageError(false);

    onChange?.(e);
  };

  const handleImageLoad = () => {
    setImageError(false);
    onImageLoad?.(imageUrl);
  };

  const handleImageError = () => {
    setImageError(true);
    onImageError?.(new Error('Failed to load image'));
  };

  const hasError = error || (!isValidUrl && imageUrl.trim() !== '') || imageError;
  const showPreview = imageUrl.trim() !== '' && isValidUrl && !imageError;

  return (
    <div className="space-y-2">
      <div
        className={cn(
          'border-border/50 bg-muted/50 flex h-24 w-full items-center justify-center overflow-hidden rounded-lg border',
          showPreview && 'bg-background p-0',
          previewClassName,
        )}
      >
        {showPreview ? (
          <img
            loading="lazy"
            srcSet={imageUrl}
            src={imageUrl}
            sizes={imgSizes}
            decoding="async"
            alt="Preview"
            className="animate-in fade-in-0 max-h-24 max-w-24 object-contain blur-none transition-all duration-200 ease-in-out"
            height={imgHeight}
            width={imgWidth}
            onLoad={handleImageLoad}
            onError={handleImageError}
          />
        ) : (
          <div className="text-muted-foreground flex h-full w-full flex-col items-center justify-center gap-2 text-sm">
            {previewIcon}
            {imageUrl.trim() !== '' && !isValidUrl ? 'Invalid URL' : previewPlaceholder}
          </div>
        )}
      </div>

      <TextField
        {...textFieldProps}
        value={value}
        onChange={handleChange}
        error={hasError}
        placeholder={placeholder}
      />
    </div>
  );
}

export { ImagePreviewField };

