'use client';

import type { AuthDetails } from '@auth0/universal-components-core';
import * as React from 'react';

import { Toaster } from '@/components/auth0/shared/sonner';
import { Spinner } from '@/components/ui/spinner';
import { CoreClientContext } from '@/hooks/shared/use-core-client';
import { useCoreClientInitialization } from '@/hooks/shared/use-core-client-initialization';
import { useToastProvider } from '@/hooks/shared/use-toast-provider';
import { QueryProvider } from '@/providers/query-provider';
import { ThemeProvider } from '@/providers/theme-provider';
import type { Auth0ComponentProviderProps } from '@/types/auth-types';

/**
 * Auth0 provider for RWAs using backend proxy auth.
 * @param props - Provider configuration including domain, proxyConfig, i18n, themeSettings, toastSettings, cacheConfig, loader, and children.
 * @returns Provider component tree
 */
export const Auth0ComponentProvider = ({
  i18n,
  domain,
  proxyConfig,
  previewMode,
  themeSettings = {
    theme: 'default',
    mode: 'light',
    variables: {
      common: {},
      light: {},
      dark: {},
    },
  },
  toastSettings,
  cacheConfig,
  loader,
  children,
}: Extract<Auth0ComponentProviderProps, { mode: 'proxy' }> & { children: React.ReactNode }) => {
  const mergedToastSettings = useToastProvider(toastSettings);
  const baseUrl = proxyConfig.baseUrl;

  const memoizedAuthDetails = React.useMemo<AuthDetails>(
    () => ({
      domain,
      authProxyUrl: baseUrl,
      previewMode,
    }),
    [domain, baseUrl, previewMode],
  );

  const coreClient = useCoreClientInitialization({
    authDetails: memoizedAuthDetails,
    i18nOptions: i18n,
  });

  const coreClientValue = React.useMemo(
    () => ({
      coreClient,
    }),
    [coreClient],
  );

  const fallback = loader || (
    <div className="flex items-center justify-center min-h-[200px]">
      <Spinner />
    </div>
  );

  return (
    <ThemeProvider
      themeSettings={{
        mode: themeSettings.mode,
        variables: themeSettings.variables,
        loader,
        theme: themeSettings.theme,
      }}
    >
      {mergedToastSettings.provider === 'sonner' && (
        <Toaster
          position={mergedToastSettings.settings?.position || 'top-right'}
          closeButton={mergedToastSettings.settings?.closeButton ?? true}
          className="auth0-universal"
        />
      )}
      {coreClient ? (
        <CoreClientContext.Provider value={coreClientValue}>
          <QueryProvider cacheConfig={cacheConfig}>{children}</QueryProvider>
        </CoreClientContext.Provider>
      ) : (
        fallback
      )}
    </ThemeProvider>
  );
};

export default Auth0ComponentProvider;

'use client';

/**
 * TanStack Query provider wrapper.
 * @module query-provider
 * @internal
 */

import { isMfaRequiredError, isNotifiableError } from '@auth0/universal-components-core';
import {
  MutationCache,
  type Query,
  QueryCache,
  QueryClient,
  QueryClientProvider as TanStackQueryClientProvider,
} from '@tanstack/react-query';
import { useMemo, useState, type ReactElement, type ReactNode } from 'react';

import { GateKeeperContext } from '@/providers/gate-keeper-context';

/** Query cache configuration. */
export interface QueryCacheConfig {
  enabled?: boolean;
  staleTime?: number;
  gcTime?: number;
  refetchOnWindowFocus?: boolean | 'always';
}

/** Default cache configuration. */
export const DEFAULT_CACHE_CONFIG: Readonly<Required<QueryCacheConfig>> = {
  enabled: true,
  staleTime: 2 * 60 * 1000,
  gcTime: 5 * 60 * 1000,
  refetchOnWindowFocus: false,
};

const QUERY_RETRY_CONFIG = {
  maxRetries: 3,
  maxRetryDelay: 30_000,
  backoffMultiplier: 2,
} as const;

const MUTATION_RETRY_CONFIG = {
  maxRetries: 1,
} as const;

const DISABLED_CACHE_GC_TIME = 5 * 1000;

/**
 * Merges user config with defaults.
 * @param userConfig - User-provided cache config.
 * @returns The resolved cache configuration
 * @internal
 */
export function resolveCacheConfig(userConfig?: QueryCacheConfig): Required<QueryCacheConfig> {
  const merged: Required<QueryCacheConfig> = {
    ...DEFAULT_CACHE_CONFIG,
    ...userConfig,
  };

  if (!merged.enabled) {
    return {
      ...merged,
      staleTime: 0,
      gcTime: DISABLED_CACHE_GC_TIME,
    };
  }

  return merged;
}

/**
 * Returns true if a cached query has an error that GateKeeper should handle.
 * @param query - The cached query to check.
 * @returns Whether the query error should be intercepted by GateKeeper.
 */
function isGateKeeperError(query: Query): boolean {
  return !!query.state.error && !isNotifiableError(query.state.error);
}

/**
 * Creates a QueryClient with config and global GateKeeper error interception.
 * @param cacheConfig - Cache configuration.
 * @param setGateKeeperState - Setter for GateKeeper context state.
 * @returns The configured QueryClient instance
 * @internal
 */
function createQueryClient(
  cacheConfig: Required<QueryCacheConfig>,
  setGateKeeperState: (state: { error: Error; onRetry: () => Promise<boolean> } | null) => void,
): QueryClient {
  const queryClient = new QueryClient({
    queryCache: new QueryCache({
      onError: (error) => {
        if (!isNotifiableError(error)) {
          setGateKeeperState({
            error,
            onRetry: async () => {
              await queryClient.refetchQueries({ predicate: isGateKeeperError });
              const stillFailing = queryClient.getQueryCache().getAll().some(isGateKeeperError);
              if (!stillFailing) setGateKeeperState(null);
              return !stillFailing;
            },
          });
        }
      },
    }),
    mutationCache: new MutationCache({
      onError: (error, variables, _context, mutation) => {
        if (isMfaRequiredError(error)) {
          setGateKeeperState({
            error,
            onRetry: async () => {
              try {
                await mutation.execute(variables);
                setGateKeeperState(null);
                return true;
              } catch {
                return false;
              }
            },
          });
        }
      },
    }),
    defaultOptions: {
      queries: {
        staleTime: cacheConfig.staleTime,
        gcTime: cacheConfig.gcTime,
        refetchOnWindowFocus: cacheConfig.refetchOnWindowFocus,
        retry: (failureCount, error) =>
          !isMfaRequiredError(error) && failureCount < QUERY_RETRY_CONFIG.maxRetries,
        retryDelay: (attemptIndex: number) =>
          Math.min(
            1000 * QUERY_RETRY_CONFIG.backoffMultiplier ** attemptIndex,
            QUERY_RETRY_CONFIG.maxRetryDelay,
          ),
        refetchOnReconnect: true,
      },
      mutations: {
        retry: (failureCount, error) =>
          !isMfaRequiredError(error) && failureCount < MUTATION_RETRY_CONFIG.maxRetries,
      },
    },
  });

  return queryClient;
}

/** Props for QueryProvider. */
export interface QueryProviderProps {
  children: ReactNode;
  /** Cache config, only read on mount. */
  cacheConfig?: QueryCacheConfig;
}

/**
 * Internal TanStack Query provider wrapper.
 * @param props - Component props.
 * @param props.children - Child components.
 * @param props.cacheConfig - Cache configuration.
 * @returns The context provider component
 * @internal
 */
export function QueryProvider({ children, cacheConfig }: QueryProviderProps): ReactElement {
  const [gateKeeperState, setGateKeeperState] = useState<{
    error: Error;
    onRetry: () => Promise<boolean>;
  } | null>(null);
  const [queryClient] = useState(() =>
    createQueryClient(resolveCacheConfig(cacheConfig), setGateKeeperState),
  );

  const contextValue = useMemo(() => gateKeeperState ?? { error: null }, [gateKeeperState]);

  return (
    <GateKeeperContext.Provider value={contextValue}>
      <TanStackQueryClientProvider client={queryClient}>{children}</TanStackQueryClientProvider>
    </GateKeeperContext.Provider>
  );
}

/**
 * SPA provider using @auth0/auth0-react.
 * @module spa-provider
 */

'use client';

import { useAuth0 } from '@auth0/auth0-react';
import type { AuthDetails, BasicAuth0ContextInterface } from '@auth0/universal-components-core';
import * as React from 'react';

import { Toaster } from '@/components/auth0/shared/sonner';
import { Spinner } from '@/components/ui/spinner';
import { CoreClientContext } from '@/hooks/shared/use-core-client';
import { useCoreClientInitialization } from '@/hooks/shared/use-core-client-initialization';
import { useToastProvider } from '@/hooks/shared/use-toast-provider';
import { QueryProvider } from '@/providers/query-provider';
import { ThemeProvider } from '@/providers/theme-provider';
import type { Auth0ComponentProviderProps } from '@/types/auth-types';

/**
 * Auth0 provider for SPAs. Wraps components with required contexts.
 * @param props - Provider configuration including domain, mode, authContext, i18n, themeSettings, toastSettings, cacheConfig, loader, and children.
 * @returns Provider component tree
 */
export const Auth0ComponentProvider = (
  props: Extract<Auth0ComponentProviderProps, { mode?: 'direct' }> & { children: React.ReactNode },
) => {
  const {
    i18n,
    previewMode,
    themeSettings = {
      theme: 'default',
      mode: 'light',
      variables: {
        common: {},
        light: {},
        dark: {},
      },
    },
    toastSettings,
    cacheConfig,
    loader,
    children,
    authContext,
  } = props;
  const mergedToastSettings = useToastProvider(toastSettings);

  const auth0ReactContext = useAuth0();

  const resolvedAuthContext = React.useMemo(() => {
    if (authContext) {
      return authContext;
    }
    if (auth0ReactContext && 'isAuthenticated' in auth0ReactContext) {
      return auth0ReactContext as BasicAuth0ContextInterface;
    }

    throw new Error(
      'Auth0ContextInterface is not available. Make sure you wrap your app with Auth0Provider from @auth0/auth0-react, or pass authContext.',
    );
  }, [auth0ReactContext, authContext]);

  const memoizedAuthDetails = React.useMemo<AuthDetails>(
    () => ({
      contextInterface: resolvedAuthContext,
      previewMode,
    }),
    [resolvedAuthContext, previewMode],
  );

  const coreClient = useCoreClientInitialization({
    authDetails: memoizedAuthDetails,
    i18nOptions: i18n,
  });

  const coreClientValue = React.useMemo(
    () => ({
      coreClient,
    }),
    [coreClient],
  );

  const fallback = loader || (
    <div className="flex items-center justify-center min-h-[200px]">
      <Spinner />
    </div>
  );

  return (
    <ThemeProvider
      themeSettings={{
        mode: themeSettings.mode,
        variables: themeSettings.variables,
        loader,
        theme: themeSettings.theme,
      }}
    >
      {mergedToastSettings.provider === 'sonner' && (
        <Toaster
          position={mergedToastSettings.settings?.position || 'top-right'}
          closeButton={mergedToastSettings.settings?.closeButton ?? true}
          className="auth0-universal"
        />
      )}
      {coreClient ? (
        <CoreClientContext.Provider value={coreClientValue}>
          <QueryProvider cacheConfig={cacheConfig}>{children}</QueryProvider>
        </CoreClientContext.Provider>
      ) : (
        fallback
      )}
    </ThemeProvider>
  );
};

export default Auth0ComponentProvider;

/**
 * Theme provider for styling configuration.
 * @module theme-provider
 * @internal
 */

'use client';

import { applyStyleOverrides, type StylingVariables } from '@auth0/universal-components-core';
import * as React from 'react';

import { PortalContext } from '@/providers/portal-context';
import type { ThemeContextValue, ThemeInput } from '@/types/theme-types';

/** Default empty style overrides. */
const defaultStyleOverrides: StylingVariables = { common: {}, light: {}, dark: {} };

/**
 * Theme context for accessing theme settings.
 * @internal
 * @returns The context provider component
 */
export const ThemeContext = React.createContext<ThemeContextValue>({
  isDarkMode: false,
  variables: defaultStyleOverrides,
  loader: null,
});

/**
 * Provides theme configuration to the component tree.
 * @param props - Component props.
 * @param props.themeSettings - Theme settings with mode, variables, and loader.
 * @param props.children - Child components.
 * @returns Theme provider.
 * @internal
 */
export const ThemeProvider: React.FC<{
  themeSettings?: ThemeInput;
  children: React.ReactNode;
}> = ({ themeSettings, children }) => {
  const { variables, loader, mode, theme } = React.useMemo(
    () => ({
      variables: themeSettings?.variables ?? defaultStyleOverrides,
      loader: themeSettings?.loader ?? null,
      mode: themeSettings?.mode,
      theme: themeSettings?.theme ?? 'default',
    }),
    [themeSettings],
  );

  const [portalContainer, setPortalContainer] = React.useState<HTMLElement | null>(null);

  React.useEffect(() => {
    applyStyleOverrides(variables, mode, theme);
  }, [variables, mode, theme]);

  return (
    <ThemeContext.Provider value={{ isDarkMode: mode === 'dark', theme, variables, loader }}>
      <PortalContext.Provider value={portalContainer}>
        {children}
        <div className="auth0-universal" data-theme={theme} ref={setPortalContainer} />
      </PortalContext.Provider>
    </ThemeContext.Provider>
  );
};

/**
 * Auth provider configuration types.
 * @module auth-types
 */

import type { AuthDetails } from '@auth0/universal-components-core';
import type * as React from 'react';

import type { QueryCacheConfig } from '@/types/cache-types';
import type { I18nOptions } from '@/types/i18n-types';
import type { ThemeSettings } from '@/types/theme-types';
import type { ToastSettings } from '@/types/toast-types';

/** Props for Auth0ComponentProvider. */
export type Auth0ComponentProviderProps = (
  | {
      mode?: 'direct';
      authContext?: AuthDetails['contextInterface'];
      proxyConfig?: never;
    }
  | { mode: 'proxy'; domain: string; proxyConfig: { baseUrl: string } }
) & {
  i18n?: I18nOptions;
  themeSettings?: ThemeSettings;
  loader?: React.ReactNode;
  toastSettings?: ToastSettings;
  /** TanStack Query cache config. Use `{ enabled: false }` to disable. */
  cacheConfig?: QueryCacheConfig;
  previewMode?: boolean;
};

/**
 * TanStack Query cache configuration types.
 * @module cache-types
 */

/** Cache configuration options. */
export interface QueryCacheConfig {
  enabled?: boolean;
  staleTime?: number;
  gcTime?: number;
  refetchOnWindowFocus?: boolean | 'always';
}

/**
 * Internationalization configuration types.
 * @module i18n-types
 */

/** i18n configuration for Auth0 components. */
export interface I18nOptions {
  currentLanguage: string;
  fallbackLanguage?: string;
}

